def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + np.log1p(cap**2) * 18 - np.sqrt(item) * 4
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * (usage ** 1.3)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 50 * np.sin(cap * 1.7) + np.log1p(cap) * 7
            else:
                base_priority -= 60 * usage
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 22 / (i**0.9)
            for p in range(1, 4):
                fluctuation += np.log1p(abs(np.cos(cap * p * usage))) * 5 / p
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2.2 + 300 * (1 - delta ** 0.6)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.25)) * 28 / j
            if int(cap * 4.5) % 4 == 0:
                base_priority += 45 * np.tan(cap / 18)
            fluctuation += np.exp(-usage) * 30
        elif 3 < usage <= 4:
            base_priority += 1400 * (usage - 3)**2.5
            for k in range(1, 15):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.7:
                        fluctuation += 25
            if cap % 3.5 < 0.7:
                base_priority += 40 * np.sin(cap * 4)
            fluctuation -= np.cos(cap * usage) * 7
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2)**3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 30 / m
                    if m % 2 == 0:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 16 and usage > 2.5:
                        fluctuation += 18
            if cap % 1.8 < 0.6:
                base_priority += 38 * np.cos(cap * 3.5)
            fluctuation += np.sin(cap * usage) * 11
        elif 1 < usage <= 2:
            base_priority += 800 * (usage - 1) ** 4
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.55:
                    fluctuation += pwr * 28 / n
                    if n % 3 == 0:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 14 and usage > 1.6:
                        fluctuation += 22
            if cap % 1.3 < 0.4:
                base_priority += 32 * np.cos(cap * 2.5)
            fluctuation -= np.tanh(cap * usage) * 9
        elif 0.7 < usage <= 1:
            base_priority += 150 * (1 - usage)
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.06 * o:
                    fluctuation -= 10 * o
            if cap < 0.18:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4) * 26
            fluctuation += np.sin(cap * usage * 3.3) * 8
        elif 0.3 < usage <= 0.7:
            base_priority += 220 * (1 - usage) ** 1.5
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.15) * 16 / p
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.025:
                base_priority += np.sqrt(cap) * 370
            elif cap < 0.95:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 5) * 35
            fluctuation -= np.cos(cap * 2.7) * 6
        else:
            base_priority += 320 * (1 - usage) ** 2.2
            for q in range(1, 22):
                pwr = usage ** q
                fluctuation += (np.sin(pwr * np.pi / 8) - 0.20) * 18 / q
                if usage < 0.01 * q:
                    fluctuation -= 16 * q
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.1:
                base_priority += np.log1p(cap * 28) * 55
            else:
                base_priority += (cap % 7) * 40
            fluctuation += np.tanh(cap * usage) * 12
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 80
            if usage > 0.8:
                priority += 95
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 22)
        elif cap < 1.0:
            priority += 45
            if usage > 0.9:
                priority += 65
            elif usage < 0.18:
                priority -= 35
            for s in range(1, 7):
                if int(cap * 1400) % (s + 5) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 45
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.93:
                priority += 95
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 2700) % 21 == 0:
            proximity += 18
        if int(cap * 950) % 25 == 0:
            proximity -= 14
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.018:
                proximity += 22 / w
            elif diff < 0.045:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 10)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 7)
            if mod_chk == 0:
                proximity += 14 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 9):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 2.5:
            if cap % 1 < 0.05:
                priority += 45
            if (int(cap * 2700) % 27 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 7):
                if (int(cap * 650) % (bb + 10) == 3) and (usage < 0.88):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
